        m.entries.push_back({"Right Audio", {"Stereo audio right channel input. Normalizes to Left if disconnected.", "立體聲右聲道 Audio 輸入。未連接時正規化至 Left。", "ステレオオーディオ右チャンネル入力。未接続時はLeftに正規化。"}});
