        m.entries.push_back({"S&H Rate CV Attenuverter", {"Attenuverter for S&H Rate CV input (-1.0 to +1.0).", "S&H Rate CV 輸入的 Attenuverter（-1.0 至 +1.0）。", "S&H Rate CV入力用アッテヌバーター（-1.0～+1.0）。"}});
